async function main() {
  console.log('=== PIPELINE SOURATE 2 — VERSET 206 ===\n');
  await createNewRoots();
  await processVerse(206);
  await syncWordMeanings();
  console.log('\n=== PIPELINE V206 TERMINEE ===');
}

main().catch(e => console.error('FATAL:', e));
